test.describe("examples load", function()
    test.it("counter.lua loads without error", function()
        local app = test.createApp(80, 24)
        app:loadFile("../examples/counter.lua")
        local text = app:screenText()
        test.assert.contains(text, "Counter")
        app:destroy()
    end)

    test.it("todo_mvc.lua loads without error", function()
        local app = test.createApp(80, 24)
        app:loadFile("../examples/todo_mvc.lua")
        local text = app:screenText()
        test.assert.contains(text, "Todo MVC")
        app:destroy()
    end)

    test.it("dashboard.lua loads without error", function()
        local app = test.createApp(80, 24)
        app:loadFile("../examples/dashboard.lua")
        local text = app:screenText()
        test.assert.contains(text, "Dashboard")
        app:destroy()
    end)
end)
